const body = $input.first().json.body || {};
const program_name = (body.program_name || '').toUpperCase().trim();
if (!program_name) throw new Error('program_name es requerido');
return { json: { program_name } };

const prog      = $('Busca Datos Programa').first().json;
const relations = $('Busca Relaciones').all().map(i => i.json);

if (!prog.program_id) {
  throw new Error(`Programa '${$('Extrae Params').first().json.program_name}' no encontrado`);
}

const use_cache = (
  prog.doc_status === 'completed' &&
  prog.cached_checksum === prog.current_checksum &&
  prog.existing_doc_id != null
);

// Agrupa relaciones por tipo
const calls     = relations.filter(r => r.tipo === 'call');
const copybooks = relations.filter(r => r.tipo === 'copybook');
const files     = relations.filter(r => r.tipo === 'file');
const db2       = relations.filter(r => r.tipo === 'db2');

// Construye contexto estructurado para el LLM
const context = [
  calls.length     ? `PROGRAMAS QUE LLAMA:\n${calls.map(c => `- ${c.nombre} (${c.detalle}, línea ${c.extra})`).join('\n')}` : '',
  copybooks.length ? `COPYBOOKS INCLUIDOS:\n${copybooks.map(c => `- ${c.nombre} en ${c.detalle} (línea ${c.extra})`).join('\n')}` : '',
  files.length     ? `ARCHIVOS ACCEDIDOS:\n${files.map(f => `- ${f.nombre} → ${f.detalle} (${f.extra || 'tipo desconocido'})`).join('\n')}` : '',
  db2.length       ? `TABLAS DB2:\n${db2.map(d => `- ${d.detalle}.${d.nombre} [${d.extra}]`).join('\n')}` : ''
].filter(Boolean).join('\n\n');

return {
  json: {
    ...prog,
    use_cache,
    calls, copybooks, files, db2,
    relations_context: context
  }
};

