const row = $input.first().json;
return {
  json: {
    success:      true,
    from_cache:   true,
    program_name: row.program_name,
    content_md:   row.content_md,
    content_html: row.content_html,
    generated_at: row.generated_at
  }
};

const chainOut = $input.first().json;
const prog     = $('Evalúa Caché y Prepara Contexto').first().json;

const content_md = (chainOut.text || chainOut.output || '').trim();

// Convierte Markdown básico a HTML
const mdToHtml = (md) => {
  return md
    .replace(/^# (.+)$/gm,   '<h1>$1</h1>')
    .replace(/^## (.+)$/gm,  '<h2>$1</h2>')
    .replace(/^### (.+)$/gm, '<h3>$1</h3>')
    .replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>')
    .replace(/`(.+?)`/g, '<code>$1</code>')
    .replace(/^\| (.+) \|$/gm, (m) => '<tr>' + m.split('|').filter(c => c.trim()).map(c => `<td>${c.trim()}</td>`).join('') + '</tr>')
    .replace(/^- (.+)$/gm, '<li>$1</li>')
    .replace(/(<li>.*<\/li>\n?)+/g, s => `<ul>${s}</ul>`)
    .replace(/(<tr>.*<\/tr>\n?)+/g, s => `<table>${s}</table>`)
    .replace(/\n{2,}/g, '</p><p>')
    .replace(/^(?!<[h|u|t|l|p])/gm, '')
};

const body_html = mdToHtml(content_md);

const content_html = `<!DOCTYPE html>
<html lang="es">
<head><meta charset="UTF-8">
<style>
  body{font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',sans-serif;margin:0;padding:32px;max-width:900px;color:#111;line-height:1.6;}
  h1{font-size:24px;border-bottom:2px solid #3b82f6;padding-bottom:8px;color:#1e3a5f;}
  h2{font-size:18px;margin-top:32px;color:#1e40af;border-bottom:1px solid #e5e7eb;padding-bottom:4px;}
  h3{font-size:15px;color:#374151;margin-top:16px;}
  table{width:100%;border-collapse:collapse;margin:12px 0;font-size:14px;}
  td,th{border:1px solid #e5e7eb;padding:8px 12px;text-align:left;}
  tr:first-child td{background:#f1f5f9;font-weight:600;}
  tr:nth-child(even) td{background:#f9fafb;}
  code{background:#f3f4f6;padding:2px 6px;border-radius:4px;font-size:13px;font-family:monospace;}
  ul{padding-left:20px;}
  li{margin-bottom:4px;}
  .meta{background:#eff6ff;border-left:4px solid #3b82f6;padding:12px 16px;margin-bottom:24px;border-radius:4px;font-size:13px;color:#374151;}
</style>
</head>
<body>
<div class="meta">
  <strong>Programa:</strong> ${prog.program_name} &nbsp;|&nbsp;
  <strong>Líneas:</strong> ${prog.line_count || 'N/D'} &nbsp;|&nbsp;
  <strong>Generado:</strong> ${new Date().toLocaleDateString('es-AR')}
</div>
${body_html}
</body></html>`;

return {
  json: {
    program_id:       prog.program_id,
    program_name:     prog.program_name,
    version_id:       prog.version_id,
    current_checksum: prog.current_checksum,
    content_md,
    content_html
  }
};

const data = $('Genera HTML y Prepara Datos').first().json;
return {
  json: {
    success:      true,
    from_cache:   false,
    program_name: data.program_name,
    content_md:   data.content_md,
    content_html: data.content_html,
    generated_at: new Date().toISOString()
  }
};
